$renderProviderBtn = function ($provider) use ($providerBadges, $selectedProviders, $providerBadgeBlockClass, $slotRepairMojibake, $providerIconClass, $providerLogoSvg) {
    $badgeSlug = ProviderDisplayBadgeMap::slugForDisplay($provider);
    $badges    = $badgeSlug !== null ? array_slice($providerBadges[$badgeSlug] ?? [], 0, 1) : [];
    $active = in_array($provider, $selectedProviders);
    $provider = $slotRepairMojibake((string) $provider);
    $label = htmlspecialchars($provider);
    $esc = htmlspecialchars($provider, ENT_QUOTES, 'UTF-8');
    $iconClass = $providerIconClass($provider, $badgeSlug);
    $svgLogo = $providerLogoSvg($provider, $badgeSlug);
    $icon = $svgLogo !== '' ? $svgLogo : ($iconClass !== '' ? '<i class="provider-logo-icon ' . htmlspecialchars($iconClass, ENT_QUOTES, 'UTF-8') . '" aria-hidden="true"></i>' : '');
    $badge = $slotRepairMojibake((string) ($badges[0] ?? ''));
    $badgeClass = $badge !== '' ? $providerBadgeBlockClass($badge) : '';
    return '<div title="' . $esc . '" class="providerItemsInner sidebar-provider-item' . ($active ? ' active' : '') . '" role="button" tabindex="0" data-provider="' . $esc . '"><span class="providerBadgeBlock ' . htmlspecialchars($badgeClass, ENT_QUOTES, 'UTF-8') . '" data-badge="' . htmlspecialchars($badge, ENT_QUOTES, 'UTF-8') . '"></span><div class="providerItemsBtn' . ($icon !== '' ? ' has-provider-icon' : '') . '">' . $icon . '<span class="provider-list-row">' . $label . '</span></div></div>';
};

$renderOriginalCategorySvg = static function (array $category) use ($slotOriginalCategorySvgBySort): string {
    $sort = (string) ($category['sort'] ?? '');
    $svg = $slotOriginalCategorySvgBySort[$sort] ?? null;
    if (!$svg) {
        return '<i class="bc-i-default-icon ' . htmlspecialchars((string) ($category['icon'] ?? ''), ENT_QUOTES, 'UTF-8') . '" aria-hidden="true"></i>';
    }

    $paths = '';
    foreach (($svg['paths'] ?? []) as $path) {
        $paths .= '<path d="' . htmlspecialchars((string) $path, ENT_QUOTES, 'UTF-8') . '"></path>';
    }

    return '<svg xmlns="http://www.w3.org/2000/svg" viewBox="' . htmlspecialchars((string) ($svg['viewBox'] ?? '0 0 1024 1024'), ENT_QUOTES, 'UTF-8') . '" fill="currentColor" aria-hidden="true">' . $paths . '</svg>';
};

